export const allWords = (lang) => Object.values(WDB[lang] || {}).flat();
export const wordLevels = (lang) => Object.entries(WDB[lang] || {}).filter(([, arr]) => arr.length > 0).map(([lvl]) => lvl);
export const getWordLevel = (lang, wordId) =>
  Object.entries(WDB[lang] || {}).find(([, arr]) => arr.some((w) => w.id === wordId))?.[0] || "";
